from zeep import Client
import sys

def get_policy_quote(client, policy_number, customer_name):
    quote_response = client.service.get_quote({
        "policyNumber": policy_number,
        "customerName": customer_name
    })
    return quote_response

client = Client("https://insurance-service.example.com/?wsdl")

if len(sys.argv) != 3:
    print("Usage: python insurance_aggregator.py <policy_number> <customer_name>")
    sys.exit(1)

policy_number = sys.argv[1]
customer_name = sys.argv[2]
quote = get_policy_quote(client, policy_number, customer_name)
print("Quote for policy {} from customer {}: {}".format(policy_number, customer_name, quote))